#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long *B = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld",&B[i]);
        int ok=1;
        for(int i=1;i<N && ok;i++) if(B[i-1]%B[i]!=0) ok=0;
        if(!ok){
            printf("-1\n");
        }else{
            for(int i=0;i<N;i++){
                if(i) printf(" ");
                printf("%lld",B[i]);
            }
            printf("\n");
        }
        free(B);
    }
    return 0;
}

