import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        B = [int(next(it)) for _ in range(N)]
        ok = all(B[i-1] % B[i] == 0 for i in range(1, N))
        if not ok:
            out_lines.append('-1')
        else:
            out_lines.append(' '.join(map(str, B)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

